// Colebrook-White equation solver (iterative) for Darcy friction factor
function calcFrictionFactor(Re, epsilon, D_in) {
  if (Re < 2300) return 64 / Re; // Laminar
  const relRough = epsilon / D_in;
  // Swamee-Jain approximation (±1% of Colebrook)
  const f = 0.25 / Math.pow(Math.log10(relRough / 3.7 + 5.74 / Math.pow(Re, 0.9)), 2);
  return f;
}

// Full nozzle flow analysis
function calcNozzleFlow(params) {
  const {
    Q_gpm,         // Flow rate through nozzle (GPM)
    d_in,          // Inside diameter of nozzle (inches)
    tempF,         // Fluid temperature (°F)
    materialId,    // CS or SS (for roughness)
    nozzleLength,  // Effective nozzle length (inches) including projections
    service,       // For context in report
  } = params;

  const wp = getWaterProps(tempF);
  const rho = wp.rho;                          // lb/ft³
  const mu_cP = wp.mu_cP;                      // centipoise
  const mu_lbfts = mu_cP * 6.7197e-4;          // convert cP → lb/(ft·s)
  const cp = wp.cp;                            // BTU/(lb·°F)
  const k_therm = wp.k;                        // BTU/(hr·ft·°F)

  // Prandtl number: Pr = cp × μ / k
  // Units: [BTU/(lb·°F)] × [lb/(ft·s)] / [BTU/(hr·ft·°F)]
  // Need consistent units: convert k to BTU/(s·ft·°F) by dividing by 3600
  const k_s = k_therm / 3600;                  // BTU/(s·ft·°F)
  const Pr = (cp * mu_lbfts) / k_s;

  // Cross-sectional area
  const A_in2 = Math.PI * Math.pow(d_in / 2, 2);  // in²
  const A_ft2 = A_in2 / 144;                       // ft²

  // Volumetric flow rate
  const Q_ft3s = Q_gpm / 448.831;                  // ft³/s
  const Q_ft3min = Q_gpm / 7.481;                  // ft³/min

  // Velocity
  const v_fps = Q_ft3s / A_ft2;                    // ft/s

  // Mass flow rate
  const m_dot = rho * Q_ft3s;                      // lb/s
  const m_dot_hr = m_dot * 3600;                   // lb/hr

  // Reynolds number: Re = ρ × v × D / μ
  const D_ft = d_in / 12;
  const Re = (rho * v_fps * D_ft) / mu_lbfts;

  // Flow regime
  const flowRegime = Re < 2300 ? "Laminar" : Re < 4000 ? "Transitional" : "Turbulent";

  // Friction factor (Darcy-Weisbach)
  const epsilon = PIPE_ROUGHNESS[materialId] || 0.0018;
  const f_darcy = calcFrictionFactor(Re, epsilon, d_in);

  // Nozzle pressure drop (Darcy-Weisbach + minor losses)
  // ΔP = (f × L/D + ΣK) × ρv²/2
  const L_ft = nozzleLength / 12;
  const K_entrance = 0.5;    // Sharp-edged entrance (into nozzle from vessel)
  const K_exit = 1.0;        // Sudden expansion (nozzle into piping)
  const K_total = K_entrance + K_exit;

  const dP_friction_psi = f_darcy * (L_ft / D_ft) * (rho * v_fps * v_fps) / (2 * 32.174) / 144;
  const dP_minor_psi = K_total * (rho * v_fps * v_fps) / (2 * 32.174) / 144;
  const dP_total_psi = dP_friction_psi + dP_minor_psi;

  // Nusselt number (Dittus-Boelter for turbulent, Re > 10000)
  // Nu = 0.023 × Re^0.8 × Pr^0.4 (heating)
  let Nu;
  if (Re > 10000) {
    Nu = 0.023 * Math.pow(Re, 0.8) * Math.pow(Pr, 0.4);
  } else if (Re > 2300) {
    // Gnielinski correlation for transition (2300 < Re < 10000)
    const f_g = calcFrictionFactor(Math.max(Re, 3000), epsilon, d_in);
    Nu = ((f_g / 8) * (Re - 1000) * Pr) / (1 + 12.7 * Math.sqrt(f_g / 8) * (Math.pow(Pr, 2/3) - 1));
    Nu = Math.max(Nu, 3.66); // minimum for laminar
  } else {
    Nu = 3.66; // Laminar, constant wall temp
  }

  // Heat transfer coefficient h = Nu × k / D
  const h_conv = Nu * k_therm / D_ft; // BTU/(hr·ft²·°F)

  // Velocity assessment per ASHRAE
  const velocityOK = v_fps <= 8.0;
  const velocityNote = v_fps <= 4.0 ? "Excellent — well below ASHRAE 8 ft/s limit" :
    v_fps <= 6.0 ? "Good — within recommended range" :
    v_fps <= 8.0 ? "Acceptable — at upper limit of ASHRAE recommendation" :
    v_fps <= 12.0 ? "Caution — exceeds ASHRAE 8 ft/s; consider larger nozzle" :
    "WARNING — excessive velocity; increase nozzle size";

  return {
    Q_gpm, d_in, tempF,
    rho, mu_cP, mu_lbfts, cp, k_therm, Pr: Math.round(Pr * 100) / 100,
    A_in2: Math.round(A_in2 * 10000) / 10000,
    A_ft2,
    v_fps: Math.round(v_fps * 100) / 100,
    m_dot: Math.round(m_dot * 1000) / 1000,
    m_dot_hr: Math.round(m_dot_hr * 10) / 10,
    Re: Math.round(Re),
    flowRegime,
    epsilon,
    f_darcy: Math.round(f_darcy * 100000) / 100000,
    K_entrance, K_exit, K_total,
    dP_friction_psi: Math.round(dP_friction_psi * 10000) / 10000,
    dP_minor_psi: Math.round(dP_minor_psi * 10000) / 10000,
    dP_total_psi: Math.round(dP_total_psi * 10000) / 10000,
    Nu: Math.round(Nu * 10) / 10,
    h_conv: Math.round(h_conv * 10) / 10,
    velocityOK,
    velocityNote,
    nozzleLength,
    materialId,
  };
}

// ─── NOZZLE REINFORCEMENT CALCULATION (ASME VIII-1 UG-37) ───────
// Area replacement method per UG-37
function calcNozzleReinforcement(params) {
  const {
    P,          // Design pressure (psig)
    S_v,        // Allowable stress of vessel shell (psi)
    S_n,        // Allowable stress of nozzle material (psi)
    E_v,        // Joint efficiency of vessel shell
    E_n,        // Joint efficiency of nozzle (1.0 for seamless pipe)
    t_vessel,   // Nominal thickness of vessel shell (in)
    t_nozzle,   // Nominal thickness of nozzle neck wall (in)
    R_vessel,   // Inside radius of vessel shell (in)
    d,          // Finished diameter of opening in corroded condition (in)
    nozzleOD,   // Nozzle pipe OD (in)
    CA,         // Corrosion allowance (in)
    inHead,     // Boolean: true if nozzle is in the head
    headD,      // Vessel ID (for head t_r calculation)
    weldLeg,    // Fillet weld leg size (in)
  } = params;

  // f_r1 = S_n / S_v — strength reduction factor (nozzle vs shell)
  const f_r1 = Math.min(1.0, S_n / S_v);
  // f_r2 = S_n / S_v for nozzle outward
  const f_r2 = f_r1;
  // F = correction factor = 1.0 for nozzles perpendicular to shell
  const F = 1.0;

  // Required thickness of shell (corroded), per UG-27
  const t_r_shell = (P * R_vessel) / (S_v * E_v - 0.6 * P);
  // Required thickness of head (corroded), per UG-32(d) for 2:1 SE
  const t_r_head = (P * headD) / (2 * S_v * E_v - 0.2 * P);
  // Use appropriate t_r
  const t_r = inHead ? t_r_head : t_r_shell;

  // Required thickness of nozzle wall (as a cylinder), per UG-27
  const R_n = (nozzleOD / 2 - t_nozzle); // nozzle inside radius (uncorroded)
  const t_rn = (P * (R_n + CA)) / (S_n * E_n - 0.6 * P);

  // Corroded thicknesses
  const t_c = t_vessel - CA;     // corroded vessel thickness
  const t_nc = t_nozzle - CA;    // corroded nozzle thickness

  // UG-40: Limits of reinforcement
  // Parallel to vessel: d or R_n + t_nc + t_c, whichever is larger
  const limit_parallel = Math.max(d, R_n + t_nc + t_c);
  // Perpendicular (outward): smaller of 2.5*t_c or 2.5*t_nc + t_e
  const limit_perp = Math.min(2.5 * t_c, 2.5 * t_nc);

  // A_required = d × t_r × F + 2 × t_nc × t_r × F × (1 - f_r1)
  // When f_r1 = 1.0 (same material): A_required = d × t_r × F
  const A_req = d * t_r * F + 2 * t_nc * t_r * F * (1 - f_r1);

  // A1: Excess thickness in vessel wall (larger of two methods)
  const A1_a = d * (E_v * t_c - F * t_r) - 2 * t_nc * (E_v * t_c - F * t_r) * (1 - f_r1);
  const A1_b = 2 * (E_v * t_c - F * t_r) * (t_c + t_nc);
  const A1 = Math.max(0, Math.max(A1_a, A1_b));

  // A2: Excess thickness in nozzle wall (outward, smaller of two methods)
  const A2_a = 5 * (t_nc - t_rn) * f_r2 * t_c;
  const A2_b = 5 * (t_nc - t_rn) * f_r2 * t_nc;
  const A2 = Math.max(0, Math.min(A2_a, A2_b));

  // A3: Area of fillet welds
  // Two fillet welds: one inner (shell-to-nozzle), one outer
  // A3 = 2 × (0.5 × weldLeg²) for each weld
  const A3 = 2 * 0.5 * weldLeg * weldLeg;

  const A_available = A1 + A2 + A3;
  const passes = A_available >= A_req;

  // If pad is needed
  const A_pad_needed = passes ? 0 : A_req - A_available;
  // Pad width: extend to limit_parallel or use standard 2×d pad OD
  const padOD = passes ? 0 : Math.min(2 * nozzleOD + 2, limit_parallel * 2 + nozzleOD);
  const padThk = passes ? 0 : (A_pad_needed > 0 ? Math.ceil(A_pad_needed / (padOD - nozzleOD) * 16) / 16 : 0);

  // UG-36(c)(3) exemption check: small nozzle exemption
  // NPS ≤ 3.5" and shell OD ≤ 60", or NPS ≤ 2-3/8" and shell OD > 60"
  const npsSize = (nozzleOD < 1) ? 0.25 : // approximate NPS from OD
    (nozzleOD < 1.2) ? 0.5 : (nozzleOD < 1.4) ? 0.75 :
    (nozzleOD < 1.7) ? 1.0 : (nozzleOD < 2) ? 1.25 :
    (nozzleOD < 2.5) ? 1.5 : (nozzleOD < 3) ? 2.0 :
    (nozzleOD < 4) ? 3.0 : 4.0;
  const shellOD = 2 * R_vessel + 2 * t_vessel;
  const exemptSmall = (shellOD <= 60 && npsSize <= 3.5) || (shellOD > 60 && npsSize <= 2.375);
  // Exemption only applies if: opening is in shell/head, nozzle wall is Sch40 min,
  // and the opening is reinforced by excess shell thickness
  const exemptCondition = exemptSmall && t_nc >= t_rn && (E_v * t_c >= t_r);

  return {
    d, t_r, t_rn, t_c, t_nc, f_r1, f_r2, F,
    A_req: Math.round(A_req * 10000) / 10000,
    A1: Math.round(A1 * 10000) / 10000,
    A2: Math.round(A2 * 10000) / 10000,
    A3: Math.round(A3 * 10000) / 10000,
    A_available: Math.round(A_available * 10000) / 10000,
    passes, A_pad_needed: Math.round(A_pad_needed * 10000) / 10000,
    padOD, padThk,
    exemptSmall, exemptCondition,
    npsSize, t_r_shell, t_r_head, nozzleOD, weldLeg,
    E_v, E_n, S_v, S_n, P,
  };
}
